INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('138-4-000066',1,1,1,1,1,'좁은 지하 구조로 인한 운전 난이도가 높습니다. 제한된 공간에서 운전 스트레스가 크며, 후기에서 확인된 과도한 보행자 충돌 및 갈등 사례로 보아 주차장 이용객들의 교통 예절이 좋지 않은 편입니다. 초보운전자에게는 강력히 비추천합니다.','null','2026-03-07 13:17:17','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('KA-20516447',1,1,1,1,1,'운전면허 굴절코스 수준의 극도로 좁은 설계입니다. 출입구가 S자 형태로 경사로 진입이 어렵고, 커브 구간의 연석이 매우 위험합니다. 초보운전자는 강력히 비추천하며, 경험이 많은 운전자도 신중한 조작이 필요합니다.','null','2026-03-07 13:17:00','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('KA-20563023',1,1,1,1,1,'극도로 좁은 진입로와 통로로 인해 초보운전자에게 매우 위험합니다. 사이드미러 손상, 연석 긁힘, 후진 시 뒷차 압박 등 다중 위험요소가 있습니다. 큼직한 차량이나 초보운전자는 반드시 피해야 하며, 경험 많은 운전자도 신중한 조작이 필요합니다.','null','2026-03-07 13:16:55','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('KA-492383927',1,1,1,1,1,'역대급 난이도의 헬 주차장입니다. 연석 휠 손상이 빈번하게 보고되고 있어 초보운전자는 피하시기를 강력히 권장합니다. 진입로부터 주차면, 통로 전반에 걸쳐 매우 협소하고 복잡한 구조로 판단됩니다. 경험 많은 운전자도 조심스러워하는 수준입니다.','null','2026-03-07 13:17:27','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1267337295_375080801',1,1,1,1,1,'제공된 후기는 주차장 난이도와 무관한 아파트 선택 상담 내용입니다. 주차장 특성에 대한 구체적 정보가 없어 평가 불가능하나, ''극악 난이도'' 큐레이션 사유와 ''hell 주차장'' 태그를 고려할 때 초보운전자에게 강력히 비추천합니다.','null','2026-03-07 13:46:50','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1268470024_375305014',1,1,1,1,1,'극도로 좁은 진입로와 직각 구조로 인해 초보운전자는 피해야 합니다. 사이드 미러 손상 위험이 크고, 큰 차량(SUV 등)은 진입 자체가 어렵습니다. 숙련된 운전자도 신중함이 필요한 수준입니다.','null','2026-03-07 13:46:35','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1268767457_375321777',1,1,1,1,1,'극악난이도 주차장으로 초보운전자에게 강력히 비추천합니다. 주차면이 매우 좁아 평행주차가 어렵고, 통로 폭이 협소합니다. 출차 시 일방통행 구조로 인한 혼잡이 발생하며, 보행자와 자전거 통행이 많아 주의가 필요합니다. 피할 수 있다면 다른 주차장 이용을 권장합니다.','null','2026-03-07 13:46:25','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1269749151_375637067',1,1,1,1,1,'1979년 건설된 건물로 당시 소형차 기준으로 설계되어 현대 차량에는 매우 좁습니다. 진입로와 통로 모두 협소하여 초보운전자는 접근 불가 수준입니다. 벤틀리 같은 대형차는 물론 일반 중형차도 진입 및 주차에 심각한 어려움이 예상됩니다.','null','2026-03-07 13:46:46','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1269855603_373953689',1,1,1,1,1,'충돌위험이 높은 매우 어려운 주차장입니다. 후진 입차를 권장할 정도로 진입로나 주차 공간이 협소하고 복잡한 것으로 보입니다. 초보운전자는 피하시기를 강력 권장합니다.','null','2026-03-07 13:46:55','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1270451516_372595860',2,2,2,2,2,'역대급 경사도의 급경사 진입 및 하강이 특징입니다. 후기에서 ''진짜 힘들다''는 평가가 있으며, 반경이 좁게 설계되어 있어 초보운전자에게 어렵습니다. 숙련된 운전 실력이 필요한 헬 주차장이므로 피하기를 권장합니다.','null','2026-03-07 13:46:41','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1270516135_375056900',1,1,1,1,1,'강남 L7호텔 주차장은 초보운전자에게 매우 위험합니다. 좁은 회전 공간으로 인해 차량 손상 사고가 빈번하게 발생하며, 큰 차량(SUV 등)은 특히 주의가 필요합니다. 회전 시 차체 긁힘 위험이 높으므로 피하는 것을 강력히 추천합니다.','null','2026-03-07 13:46:21','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1270533527_370804788',1,1,1,1,1,'초보운전자 절대 비추천. 좁은 회전반경에서 올라가는 차와 내려가는 차가 섞여 있어 핸들 조작이 매우 어렵습니다. 주말 만차 시간대는 주차관리원이 없을 경우 지옥 같은 상황이 발생합니다. 큰 차량은 긁힐 위험이 높으니 피하세요.','null','2026-03-07 13:46:31','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1271320844_376009718',1,1,1,1,1,'지하주차장 진입로와 내부 통로가 매우 좁아 초보운전자에게 강력 비추천합니다. 차량 크기가 조금만 커도 진입 및 주차 중 범퍼 손상 위험이 높습니다. 실제 이용자들이 차량 긁힘 사례를 보고했으므로 안전한 다른 주차장 이용을 권장합니다.','null','2026-03-07 13:16:51','null','null','null',1);
